package ndef

import (
	"bytes"
	"encoding/hex"
	"io"
	"reflect"
	"testing"
)

func TestNDEF(t *testing.T) {
	tests := []struct {
		ndef    string
		records []string
	}{
		{
			"0313d1010f5402656e48656c6c6f20776f726c6421fe",
			[]string{"Hello world!"},
		},
		{
			"0310d1010c55046578616d706c652e636f6dfe",
			[]string{"https://example.com"},
		},
		{
			// With a proprietary TLV key (0x01).
			"0103a00c340342d1013e5402656e7369676e20776564642068617262206865617220616c6d6f2061757468206c61746920616c726520686f62622064726166206f6e636520726f7365fe",
			[]string{"sign wedd harb hear almo auth lati alre hobb draf once rose"},
		},
		{
			// Multiple records.
			"032391010f5402656e48656c6c6f20776f726c642151010c55046578616d706c652e636f6dfe",
			[]string{""},
		},
		{
			"9101085402656e68656a73615101075402656e68656a32",
			[]string{"from Android writer"},
		},
		{
			"",
			[]string{"bitcoin descriptor from Q"},
		},
	}
	for _, test := range tests {
		data, err := hex.DecodeString(test.ndef)
		if err != nil {
			t.Fatal(err)
		}
		r := NewReader(bytes.NewBuffer(data))
		buf := make([]byte, 4096)
		var records []string
		for {
			n, err := r.Read(buf)
			got := buf[:n]
			t.Log(string(got), err)
			if len(got) > 0 {
				records = append(records, string(got))
			}
			if err != nil {
				if err == io.EOF {
					break
				}
				t.Fatalf("%x failed to decode: %v", data, err)
			}
		}
		if !reflect.DeepEqual(records, test.records) {
			t.Fatalf("%x decoded to %s, expected %s", data, records, test.records)
		}
	}
}
